import { useEffect } from 'react';
import { Stack } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
import { AuthProvider, useAuth } from '../context/AuthContext';
import { ThemeProvider } from '../context/ThemeContext';
import { NotificationProvider } from '../context/NotificationContext';
import { useNotifications } from '../hooks/useNotifications';
import socketService from '../services/socketService';

function RootLayoutNav() {
  const { isAuthenticated, user } = useAuth();

  useEffect(() => {
    // Initialize socket connection when authenticated
    if (isAuthenticated && user?.id) {
      // Connect socket with user credentials
      socketService
        .connect(user.id, 'staff')
        .then(() => {
          console.log('Socket connected successfully');
        })
        .catch((error) => {
          console.error('Socket connection failed:', error);
        });

      // Set up socket event listeners
      socketService.on('homework_created', (data) => {
        console.log('New homework created:', data);
      });

      socketService.on('leave_status_updated', (data) => {
        console.log('Leave status updated:', data);
      });

      socketService.on('teacher_attendance_marked', (data) => {
        console.log('Teacher attendance marked:', data);
      });

      // Chat event listeners (global)
      socketService.on('new_message', (data) => {
        console.log('New message received:', data);
      });

      socketService.on('message_notification', (data) => {
        console.log('Message notification:', data);
      });

      socketService.on('user_typing', (data) => {
        console.log('User typing:', data);
      });

      socketService.on('user_status', (data) => {
        console.log('User status changed:', data);
      });

      socketService.on('message_read', (data) => {
        console.log('Message read:', data);
      });
    }

    // Cleanup function runs on unmount or when dependencies change
    return () => {
      if (socketService.isConnected()) {
        socketService.disconnect();
      }
    };
  }, [isAuthenticated, user?.id]);

  // Initialize push notifications
  const { pushToken, notificationPermission } = useNotifications();

  return (
    <>
      <StatusBar style="auto" />
      <Stack screenOptions={{ headerShown: false }}>
        <Stack.Screen name="index" />
        <Stack.Screen name="(tabs)" options={{ headerShown: false }} />
      </Stack>
    </>
  );
}

export default function RootLayout() {
  return (
    <ThemeProvider>
      <NotificationProvider>
        <AuthProvider>
          <RootLayoutNav />
        </AuthProvider>
      </NotificationProvider>
    </ThemeProvider>
  );
}

import { Tabs } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { View, Text } from 'react-native';
import { useTheme } from '../../context/ThemeContext';

export default function TabLayout() {
  const { colors } = useTheme();

  return (
    <Tabs
      screenOptions={{
        tabBarActiveTintColor: colors.primary,
        tabBarInactiveTintColor: colors.textSecondary,
        headerShown: true,
        headerStyle: {
          backgroundColor: colors.background,
          elevation: 0,
          shadowOpacity: 0,
          borderBottomWidth: 0,
          height: 80,
        },
        headerTitleStyle: {
          fontWeight: '700',
          fontSize: 32,
          color: colors.text,
        },
        headerTitleContainerStyle: {
          paddingHorizontal: 20,
        },
        headerTintColor: colors.text,
        tabBarStyle: {
          backgroundColor: colors.background,
          borderTopWidth: 1,
          borderTopColor: colors.border,
          elevation: 0,
          shadowOpacity: 0,
          height: 80,
          paddingBottom: 24,
          paddingTop: 8,
        },
        tabBarLabelStyle: {
          fontSize: 10,
          fontWeight: '500',
        },
      }}
    >
      <Tabs.Screen
        name="index"
        options={{
          title: 'Dashboard',
          headerShown: false,
          tabBarIcon: ({ color, size }) => (
            <Ionicons name="home" size={24} color={color} />
          ),
        }}
      />
      <Tabs.Screen
        name="timetable"
        options={{
          title: 'Timetable',
          tabBarIcon: ({ color, size }) => (
            <Ionicons name="calendar-clear" size={24} color={color} />
          ),
        }}
      />
      <Tabs.Screen
        name="chat"
        options={{
          title: 'Messages',
          headerShown: false,
          tabBarIcon: ({ color, size }) => (
            <Ionicons name="chatbubbles" size={24} color={color} />
          ),
        }}
      />
      <Tabs.Screen
        name="profile"
        options={{
          title: 'Profile',
          tabBarIcon: ({ color, size }) => (
            <Ionicons name="person-circle" size={26} color={color} />
          ),
        }}
      />
    </Tabs>
  );
}

