import React, { useEffect, useState, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  ActivityIndicator,
  Alert,
  SafeAreaView,
  StatusBar,
  RefreshControl,
} from 'react-native';
import { useAuth } from '../../context/AuthContext';
import api from '../../services/api';
import { useTheme } from '../../context/ThemeContext';

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

export default function TimetableScreen() {
  const { user } = useAuth();
  const { colors } = useTheme();
  const [timetable, setTimetable] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const loadTimetable = useCallback(async () => {
    if (!user?.id) return;
    try {
      const data = await api.getTimetable(user.id);
      setTimetable(data);
    } catch (error) {
      console.error('Error loading timetable:', error);
      Alert.alert('Error', 'Failed to load timetable. Please try again.');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [user?.id]);

  useEffect(() => {
    loadTimetable();
  }, [loadTimetable]);

  const onRefresh = useCallback(() => {
    setRefreshing(true);
    loadTimetable();
  }, [loadTimetable]);

  if (loading) {
    return (
      <SafeAreaView style={[styles.centerContainer, { backgroundColor: colors.backgroundGray }]}>
        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
        <ActivityIndicator size="large" color={colors.primary} />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: colors.backgroundGray }]}>
      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
      <ScrollView
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} colors={[colors.primary]} tintColor={colors.primary} />
        }
      >
        {DAYS.map((day) => {
          const daySchedule = timetable?.[day] || [];
          return (
            <View key={day} style={[styles.dayCard, { backgroundColor: colors.background }]}>
              <Text style={[styles.dayTitle, { color: colors.text }]}>{day}</Text>
              {daySchedule.length > 0 ? (
                daySchedule.map((period: any, index: number) => (
                  <View
                    key={index}
                    style={[
                      styles.periodCard,
                      { backgroundColor: colors.inputBackground, borderLeftColor: colors.primary }
                    ]}
                  >
                    <View style={styles.periodHeader}>
                      <Text style={[styles.periodNumber, { color: colors.primary }]}>{period.subject}</Text>
                      {period.room && (
                        <Text style={[styles.roomText, { color: colors.textSecondary }]}>Period {period.periodIndex} • Room: {period.room}</Text>
                      )}
                    </View>
                    {period.classId && (
                      <Text style={[styles.classText, { color: colors.textSecondary }]}>
                        Class {period.classId.name} {period.classId.section}
                      </Text>
                    )}
                  </View>
                ))
              ) : (
                <Text style={[styles.noClassesText, { color: colors.textSecondary }]}>No classes scheduled</Text>
              )}
            </View>
          );
        })}
        <View style={{ height: 24 }} />
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  centerContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  dayCard: {
    marginHorizontal: 16,
    marginVertical: 8,
    padding: 16,
    borderRadius: 16,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.08,
    shadowRadius: 8,
    elevation: 2,
  },
  dayTitle: {
    fontSize: 20,
    fontWeight: '700',
    marginBottom: 16,
  },
  periodCard: {
    padding: 14,
    marginBottom: 10,
    borderRadius: 12,
    borderLeftWidth: 4,
  },
  periodHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 6,
  },
  periodNumber: {
    fontSize: 16,
    fontWeight: '700',
  },
  roomText: {
    fontSize: 13,
    fontWeight: '500',
  },
  subjectText: {
    fontSize: 15,
    fontWeight: '600',
    marginBottom: 4,
  },
  classText: {
    fontSize: 13,
  },
  noClassesText: {
    fontStyle: 'italic',
    padding: 12,
    textAlign: 'center',
  },
});

import React, { useEffect, useState, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  Alert,
  SafeAreaView,
  StatusBar,
  Image,
} from 'react-native';
import { useAuth } from '../../context/AuthContext';
import { useRouter } from 'expo-router';
import { useTheme } from '../../context/ThemeContext';
import api from '../../services/api';
import LeaveApplicationModal from '../../components/LeaveApplicationModal';
import SyncIndicator from '../../components/SyncIndicator';
import { useStaffProfile } from '../../hooks/useStaffProfile';
import { Ionicons } from '@expo/vector-icons';

export default function ProfileScreen() {
  const { user, logout } = useAuth();
  const router = useRouter();
  const { colors } = useTheme();
  const { profile, syncStatus, refetch } = useStaffProfile();
  const [leaves, setLeaves] = useState<any[]>([]);
  const [showLeaveModal, setShowLeaveModal] = useState(false);

  const loadLeaves = useCallback(async () => {
    if (!user?.id) return;
    try {
      const data = await api.getTeacherLeaves(user.id, 'pending');
      setLeaves(data);
    } catch (error) {
      console.error('Error loading leaves:', error);
      Alert.alert('Error', 'Failed to load leave requests. Please try again.');
    }
  }, [user?.id]);

  useEffect(() => {
    loadLeaves();
  }, [loadLeaves]);

  const handleLogout = useCallback(() => {
    Alert.alert('Logout', 'Are you sure you want to logout?', [
      { text: 'Cancel', style: 'cancel' },
      {
        text: 'Logout',
        style: 'destructive',
        onPress: logout,
      },
    ]);
  }, [logout]);

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: colors.backgroundGray }]}>
      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
      <ScrollView>
        {/* Profile Header */}
        <View style={[styles.header, { backgroundColor: colors.backgroundGray }]}>
          <View style={[styles.avatarContainer, { backgroundColor: colors.primary + '20', shadowColor: colors.primary }]}>
            {profile?.picture ? (
              <Image
                source={{ uri: profile.picture }}
                style={styles.avatarImage}
                resizeMode="cover"
              />
            ) : (
              <Text style={[styles.avatarText, { color: colors.primary }]}>
                {user?.name?.charAt(0).toUpperCase()}
              </Text>
            )}
          </View>
          <Text style={[styles.name, { color: colors.text }]}>{user?.name}</Text>
          <Text style={[styles.code, { color: colors.textSecondary }]}>{user?.code}</Text>
          <View style={[styles.roleBadge, { backgroundColor: colors.primary + '20' }]}>
            <Text style={[styles.role, { color: colors.primary }]}>{user?.role}</Text>
          </View>

          {/* Sync Indicator */}
          <View style={styles.syncContainer}>
            <SyncIndicator status={syncStatus} />
          </View>
        </View>

        {/* Info Section */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>Personal Information</Text>
          <View style={[styles.card, { backgroundColor: colors.background }]}>
            <InfoRow icon="mail-outline" label="Email" value={profile?.email || user?.email} colors={colors} />
            <InfoRow icon="call-outline" label="Phone" value={profile?.phone || user?.phone} colors={colors} last />
          </View>
        </View>

        {/* Class Teacher Section */}
        {user?.classes && user.classes.length > 0 && (
          <View style={styles.section}>
            <Text style={[styles.sectionTitle, { color: colors.text }]}>Class Teacher</Text>
            <View style={[styles.card, { backgroundColor: colors.background }]}>
              {user.classes.map((cls: any, index: number) => (
                <View key={cls.id} style={[styles.classRow, index < user.classes.length - 1 && { borderBottomWidth: 1, borderBottomColor: colors.border }]}>
                  <View style={[styles.classIconContainer, { backgroundColor: colors.primary + '20' }]}>
                    <Ionicons name="school-outline" size={22} color={colors.primary} />
                  </View>
                  <View style={styles.classInfo}>
                    <Text style={[styles.className, { color: colors.text }]}>{cls.name}</Text>
                    <Text style={[styles.classSection, { color: colors.textSecondary }]}>Section {cls.section}</Text>
                  </View>
                  <Ionicons name="chevron-forward" size={20} color={colors.textSecondary} />
                </View>
              ))}
            </View>
          </View>
        )}

        {/* Pending Leaves */}
        {leaves.length > 0 && (
          <View style={styles.section}>
            <Text style={[styles.sectionTitle, { color: colors.text }]}>Pending Leave Requests</Text>
            <View style={[styles.card, { backgroundColor: colors.background }]}>
              {leaves.map((leave, index) => (
                <View key={leave._id} style={[styles.leaveRow, index < leaves.length - 1 && { borderBottomWidth: 1, borderBottomColor: colors.border }]}>
                  <View style={[styles.leaveIconContainer, { backgroundColor: colors.inputBackground }]}>
                    <Ionicons name="time-outline" size={22} color="#F5A623" />
                  </View>
                  <View style={styles.leaveInfo}>
                    <Text style={[styles.leaveType, { color: colors.text }]}>{leave.leaveType}</Text>
                    <Text style={[styles.leaveDates, { color: colors.textSecondary }]}>
                      {new Date(leave.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - {new Date(leave.endDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                    </Text>
                  </View>
                  <View style={[styles.leaveDaysBadge, { backgroundColor: colors.backgroundGray }]}>
                    <Text style={[styles.leaveDaysText, { color: colors.textSecondary }]}>{leave.days} days</Text>
                  </View>
                </View>
              ))}
            </View>
          </View>
        )}

        {/* Quick Actions */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>Quick Actions</Text>
          <View style={[styles.card, { backgroundColor: colors.background }]}>
            <ActionRow
              icon="create-outline"
              label="Edit Profile"
              onPress={() => router.push('/edit-profile')}
              colors={colors}
            />
            <ActionRow
              icon="camera-outline"
              label="Change Photo"
              onPress={() => router.push('/profile-photo')}
              colors={colors}
            />
            <ActionRow
              icon="time-outline"
              label="Apply for Leave"
              onPress={() => setShowLeaveModal(true)}
              colors={colors}
            />
            <ActionRow
              icon="card-outline"
              label="My Payslips"
              onPress={() => router.push('/payslips')}
              colors={colors}
            />
            <ActionRow icon="megaphone-outline" label="Announcements" colors={colors} last />
          </View>
        </View>

        {/* Settings */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>Settings</Text>
          <View style={[styles.card, { backgroundColor: colors.background }]}>
            <ActionRow
              icon="settings-outline"
              label="App Settings"
              onPress={() => router.push('/settings')}
              colors={colors}
              last
            />
          </View>
        </View>

        {/* Logout */}
        <TouchableOpacity style={[styles.logoutBtn, { backgroundColor: colors.error + '20' }]} onPress={handleLogout}>
          <Ionicons name="log-out-outline" size={20} color={colors.error} />
          <Text style={[styles.logoutText, { color: colors.error }]}>Logout</Text>
        </TouchableOpacity>

        <Text style={[styles.version, { color: colors.textSecondary }]}>Staff App v1.0.0</Text>

        <LeaveApplicationModal
          visible={showLeaveModal}
          teacherId={user?.id || ''}
          onClose={() => setShowLeaveModal(false)}
          onSuccess={() => {
            loadLeaves();
            refetch();
            setShowLeaveModal(false);
          }}
        />
      </ScrollView>
    </SafeAreaView>
  );
}

function InfoRow({ icon, label, value, colors, last }: { icon: string; label: string; value?: string; colors: any; last?: boolean }) {
  return (
    <View style={[styles.infoRow, !last && { borderBottomWidth: 1, borderBottomColor: colors.border }]}>
      <View style={styles.infoLeft}>
        <Ionicons name={icon as any} size={20} color={colors.textSecondary} style={styles.infoIcon} />
        <Text style={[styles.infoLabel, { color: colors.textSecondary }]}>{label}</Text>
      </View>
      <Text style={[styles.infoValue, { color: colors.text }]}>{value || '-'}</Text>
    </View>
  );
}

function ActionRow({ icon, label, onPress, colors, last }: { icon: string; label: string; onPress?: () => void; colors: any; last?: boolean }) {
  return (
    <TouchableOpacity style={[styles.actionRow, !last && { borderBottomWidth: 1, borderBottomColor: colors.border }]} onPress={onPress}>
      <View style={styles.actionLeft}>
        <Ionicons name={icon as any} size={22} color={colors.text} style={styles.actionIcon} />
        <Text style={[styles.actionText, { color: colors.text }]}>{label}</Text>
      </View>
      <Ionicons name="chevron-forward" size={20} color={colors.textSecondary} />
    </TouchableOpacity>
  );
}

