import React, { useEffect, useState, useCallback, useRef } from 'react';
import { LinearGradient } from 'expo-linear-gradient';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  ActivityIndicator,
  RefreshControl,
  Alert,
  SafeAreaView,
  Platform,
  StatusBar,
} from 'react-native';
import { useRouter, useSegments } from 'expo-router';
import { useAuth } from '../../context/AuthContext';
import api from '../../services/api';
import { format } from 'date-fns';
import { Ionicons } from '@expo/vector-icons';
import { GuidedTour, DEFAULT_TOUR_STEPS } from '../../components';
import { useGuidedTour } from '../../hooks';
import { useTheme } from '../../context/ThemeContext';

interface DashboardData {
  teacher: {
    id: string;
    name: string;
    photo?: string;
  };
  classTeacher: {
    name: string;
    section: string;
  } | null;
  attendance: {
    status: string | null;
    inTime: string | null;
  };
  timetable: any[];
  substitutions: any[];
  gatePasses: any[];
  appointments: any[];
  unreadAnnouncements: number;
}

export default function DashboardScreen() {
  const { user, isLoading: authLoading } = useAuth();
  const { colors } = useTheme();
  const router = useRouter();
  const segments = useSegments();
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [debugInfo, setDebugInfo] = useState<string>('');

  // Track if dashboard has been loaded for current user to prevent duplicate calls
  const hasLoadedRef = useRef(false);
  const isLoadingRef = useRef(false);

  // Guided tour
  const tour = useGuidedTour({
    steps: DEFAULT_TOUR_STEPS,
    onComplete: () => {
      // Return to dashboard after tour completes
      router.replace('/(tabs)');
    },
  });

  const loadDashboard = useCallback(async () => {
    // Prevent concurrent requests
    if (isLoadingRef.current) {
      console.log('Dashboard load already in progress, skipping');
      return;
    }

    if (!user?.id) {
      console.log('No user ID available');
      setDebugInfo('No user ID available');
      setLoading(false);
      setRefreshing(false);
      return;
    }

    // Prevent duplicate loads for same user
    if (hasLoadedRef.current && !refreshing) {
      console.log('Dashboard already loaded for user:', user.id);
      return;
    }

    isLoadingRef.current = true;
    console.log('Loading dashboard for user:', user.id);
    setDebugInfo(`Loading dashboard for user: ${user.id}`);

    try {
      const dashboardData = await api.getDashboardData(user.id);
      console.log('Dashboard data loaded successfully');
      setDebugInfo('Dashboard data loaded successfully');
      setData(dashboardData);
      hasLoadedRef.current = true;
    } catch (error) {
      console.error('Error loading dashboard:', error);
      const errorMsg = error instanceof Error ? error.message : 'Unknown error';
      setDebugInfo(`Error: ${errorMsg}`);

      // Show more helpful error message based on error type
      if (error instanceof Error && error.name === 'AbortError') {
        Alert.alert(
          'Connection Timeout',
          'The server is taking too long to respond. Please check your network connection and try again.',
          [
            { text: 'Cancel', style: 'cancel' },
            {
              text: 'Retry', onPress: () => {
                hasLoadedRef.current = false;
                loadDashboard();
              }
            }
          ]
        );
      } else {
        Alert.alert(
          'Error',
          'Failed to load dashboard data. Please try again.',
          [
            { text: 'Cancel', style: 'cancel' },
            {
              text: 'Retry', onPress: () => {
                hasLoadedRef.current = false;
                loadDashboard();
              }
            }
          ]
        );
      }
    } finally {
      setLoading(false);
      setRefreshing(false);
      isLoadingRef.current = false;
    }
  }, [user?.id, refreshing]);

  // Load dashboard when user changes, but prevent duplicate loads
  useEffect(() => {
    // Reset loaded state when user changes
    if (user?.id) {
      hasLoadedRef.current = false;
    }
    loadDashboard();
  }, [user?.id]); // Only depend on user.id, not loadDashboard function

  // Debug logging - console only, no state updates to prevent re-renders
  useEffect(() => {
    const state = {
      authLoading,
      loading,
      hasUser: !!user,
      userId: user?.id,
      hasData: !!data
    };
    console.log('Dashboard state:', state);
    // Note: Removed setDebugInfo to prevent infinite re-render loop
  }, [authLoading, loading, user, data]);

  // Start tour when dashboard is first loaded
  useEffect(() => {
    // Wait for navigation to be ready and screen to render
    if (!loading && !authLoading && data) {
      const timer = setTimeout(() => {
        tour.start();
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [loading, authLoading, data]);

  const onRefresh = useCallback(() => {
    hasLoadedRef.current = false; // Allow reload
    setRefreshing(true);
    loadDashboard();
  }, [loadDashboard]);

  const markAttendance = useCallback(async (status: string) => {
    if (!user?.id) return;
    try {
      await api.markTeacherAttendance(user.id, {
        status,
        inTime: status === 'present' ? format(new Date(), 'HH:mm') : undefined,
      });
      hasLoadedRef.current = false; // Allow reload
      loadDashboard();
    } catch (error) {
      console.error('Error marking attendance:', error);
      Alert.alert('Error', 'Failed to mark attendance. Please try again.');
    }
  }, [user?.id, loadDashboard]);

  const resetAttendance = useCallback(async () => {
    if (!user?.id) return;
    try {
      await api.resetTeacherAttendance(user.id);
      hasLoadedRef.current = false; // Allow reload
      loadDashboard();
    } catch (error) {
      console.error('Error resetting attendance:', error);
      Alert.alert('Error', 'Failed to reset attendance. Please try again.');
    }
  }, [user?.id, loadDashboard]);

  if (authLoading || loading) {
    return (
      <SafeAreaView style={styles.centerContainer}>
        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
        <ActivityIndicator size="large" color={colors.primary} />
        <Text style={{ marginTop: 16, color: colors.textSecondary, fontSize: 16 }}>
          {authLoading ? 'Checking authentication...' : 'Loading dashboard...'}
        </Text>
        <View style={{ marginTop: 20, padding: 16, backgroundColor: '#f0f0f0', borderRadius: 8, maxWidth: '80%' }}>
          <Text style={{ fontSize: 12, fontFamily: 'monospace', color: colors.text }}>
            {debugInfo || 'Initializing...'}
          </Text>
        </View>
      </SafeAreaView>
    );
  }

  if (!user) {
    return (
      <SafeAreaView style={styles.centerContainer}>
        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
        <Ionicons name="person-outline" size={48} color={colors.border} />
        <Text style={styles.emptyText}>No user logged in</Text>
        <TouchableOpacity
          style={[styles.attendanceButton, styles.presentButton, { marginTop: 16 }]}
          onPress={() => router.replace('/login')}
        >
          <Text style={styles.attendanceButtonText}>Go to Login</Text>
        </TouchableOpacity>
      </SafeAreaView>
    );
  }

  if (!data) {
    return (
      <SafeAreaView style={styles.centerContainer}>
        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
        <Ionicons name="alert-circle-outline" size={48} color={colors.border} />
        <Text style={styles.emptyText}>No data available</Text>
        <TouchableOpacity
          style={[styles.attendanceButton, styles.presentButton, { marginTop: 16 }]}
          onPress={loadDashboard}
        >
          <Text style={styles.attendanceButtonText}>Retry</Text>
        </TouchableOpacity>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={[styles.mainContainer, { backgroundColor: colors.background }]}>
      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
      {/* Fixed Header Section */}
      <LinearGradient
        colors={['#FF3CAC', '#784BA0', '#2B86C5']}
        start={{ x: 0, y: 0 }}
        end={{ x: 1, y: 1 }}
        style={styles.fixedHeader}
      >
        <Text style={[styles.welcomeGreeting, { color: '#FFFFFF' }]}>Good {getGreeting()},</Text>
        <Text style={[styles.welcomeName, { color: '#FFFFFF' }]}>{data.teacher.name}</Text>
        <Text style={[styles.dateText, { color: '#FFFFFFCC' }]}>{format(new Date(), 'EEEE, MMMM d')}</Text>
      </LinearGradient>

      <ScrollView
        style={styles.scrollView}
        contentContainerStyle={styles.scrollContent}
        showsVerticalScrollIndicator={false}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.primary} />
        }
      >
        <View style={[styles.overlayContainer, { backgroundColor: colors.background }]}>
          {/* Attendance Card */}
          <View style={styles.section}>
            <Text style={[styles.sectionTitle, { color: colors.text }]}>Today's Attendance</Text>
            <View style={[styles.card, { backgroundColor: colors.card }]}>
              {data.attendance.status ? (
                <>
                  <View style={styles.attendanceMarked}>
                    <View style={styles.attendanceIconContainer}>
                      <Ionicons
                        name={data.attendance.status === 'present' ? 'checkmark-circle' : 'close-circle'}
                        size={32}
                        color={data.attendance.status === 'present' ? colors.success : colors.error}
                      />
                    </View>
                    <View style={styles.attendanceInfo}>
                      <Text style={[styles.attendanceStatus, { color: colors.text }]}>
                        Marked as {data.attendance.status.charAt(0).toUpperCase() + data.attendance.status.slice(1)}
                      </Text>
                      {data.attendance.inTime && (
                        <Text style={[styles.attendanceTime, { color: colors.textSecondary }]}>Check-in: {data.attendance.inTime}</Text>
                      )}
                    </View>
                  </View>
                  <TouchableOpacity
                    style={[styles.resetButton]}
                    onPress={resetAttendance}
                  >
                    <Ionicons name="refresh-outline" size={16} color={colors.textSecondary} style={styles.resetButtonIcon} />
                    <Text style={styles.resetButtonText}>Reset Attendance</Text>
                  </TouchableOpacity>
                </>
              ) : (
                <View style={styles.attendanceActions}>
                  <TouchableOpacity
                    style={[styles.attendanceButton, styles.presentButton]}
                    onPress={() => markAttendance('present')}
                  >
                    <Ionicons name="checkmark" size={18} color={colors.white} style={styles.buttonIcon} />
                    <Text style={styles.attendanceButtonText}>Mark Present</Text>
                  </TouchableOpacity>
                  <TouchableOpacity
                    style={[styles.attendanceButton, styles.absentButton]}
                    onPress={() => markAttendance('absent')}
                  >
                    <Ionicons name="close" size={18} color={colors.white} style={styles.buttonIcon} />
                    <Text style={styles.attendanceButtonText}>Mark Absent</Text>
                  </TouchableOpacity>
                </View>
              )}
            </View>
          </View>

          {/* Class Teacher Section */}
          {data.classTeacher && (
            <View style={styles.section}>
              <Text style={[styles.sectionTitle, { color: colors.text }]}>My Class</Text>
              <View style={[styles.card, { backgroundColor: colors.card }]}>
                <View style={styles.classHeader}>
                  <View style={styles.classIconContainer}>
                    <Ionicons name="school" size={28} color={colors.primary} />
                  </View>
                  <View style={styles.classInfo}>
                    <Text style={[styles.className, { color: colors.text }]}>{data.classTeacher.name}</Text>
                    <Text style={[styles.classSection, { color: colors.textSecondary }]}>Section {data.classTeacher.section}</Text>
                  </View>
                </View>
                <View style={styles.classActions}>
                  <TouchableOpacity
                    style={[styles.classButton, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => router.push('/class-details')}
                  >
                    <Text style={[styles.classButtonText, { color: colors.text }]}>View Class</Text>
                  </TouchableOpacity>
                  <TouchableOpacity
                    style={[styles.classButton, styles.classButtonPrimary]}
                    onPress={() => router.push('/attendance')}
                  >
                    <Text style={styles.classButtonTextPrimary}>Take Attendance</Text>
                  </TouchableOpacity>
                </View>
              </View>
            </View>
          )}

          {/* Today's Schedule */}
          <View style={styles.section}>
            <View style={styles.sectionHeader}>
              <Text style={[styles.sectionTitle, { color: colors.text }]}>Today's Schedule</Text>
              <TouchableOpacity onPress={() => router.push('/(tabs)/timetable')}>
                <Text style={[styles.seeAllText, { color: colors.primary }]}>See all</Text>
              </TouchableOpacity>
            </View>
            <View style={[styles.card, { backgroundColor: colors.card }]}>
              {data.timetable.length > 0 ? (
                data.timetable.map((period, index) => (
                  <View key={index} style={[styles.periodItem, index < data.timetable.length - 1 && styles.periodItemBorder]}>
                    <View style={[styles.periodNumber, { backgroundColor: colors.backgroundGray }]}>
                      <Text style={[styles.periodNumberText, { color: colors.textSecondary }]}>{period.periodIndex}</Text>
                    </View>
                    <View style={styles.periodContent}>
                      <Text style={[styles.periodSubject, { color: colors.text }]}>{period.subject}</Text>
                      <Text style={[styles.periodClass, { color: colors.textSecondary }]}>
                        {period.classId?.name} {period.classId?.section}
                      </Text>
                    </View>
                    <Ionicons name="chevron-forward" size={20} color={colors.textSecondary} />
                  </View>
                ))
              ) : (
                <View style={styles.emptyState}>
                  <Ionicons name="calendar-outline" size={40} color={colors.border} />
                  <Text style={[styles.emptyText, { color: colors.textSecondary }]}>No classes today</Text>
                </View>
              )}
            </View>
          </View>

          {/* Alerts Section */}
          {(data.substitutions.length > 0 || data.gatePasses.length > 0 || data.appointments.length > 0) && (
            <View style={styles.section}>
              <Text style={[styles.sectionTitle, { color: colors.text }]}>Notifications</Text>
              <View style={[styles.card, { backgroundColor: colors.card }]}>
                {data.substitutions.length > 0 && (
                  <View style={styles.alertItem}>
                    <View style={[styles.alertIconContainer, { backgroundColor: colors.primary + '15' }]}>
                      <Ionicons name="swap-horizontal" size={20} color={colors.primary} />
                    </View>
                    <View style={styles.alertContent}>
                      <Text style={[styles.alertTitle, { color: colors.text }]}>Substitutions Assigned</Text>
                      {data.substitutions.map((sub, index) => (
                        <Text key={index} style={[styles.alertText, { color: colors.textSecondary }]}>
                          {sub.classId.name} {sub.classId.section} • Period {sub.period}
                        </Text>
                      ))}
                    </View>
                  </View>
                )}

                {data.gatePasses.length > 0 && (
                  <View style={[styles.alertItem, data.substitutions.length > 0 && styles.alertItemBorder]}>
                    <View style={[styles.alertIconContainer, { backgroundColor: colors.success + '15' }]}>
                      <Ionicons name="exit-outline" size={20} color={colors.success} />
                    </View>
                    <View style={styles.alertContent}>
                      <Text style={[styles.alertTitle, { color: colors.text }]}>Gate Pass Requests</Text>
                      {data.gatePasses.map((pass, index) => (
                        <Text key={index} style={[styles.alertText, { color: colors.textSecondary }]}>
                          {pass.studentId.name} ({pass.studentId.rollNo})
                        </Text>
                      ))}
                    </View>
                  </View>
                )}

                {data.appointments.length > 0 && (
                  <View style={[styles.alertItem, (data.substitutions.length > 0 || data.gatePasses.length > 0) && styles.alertItemBorder]}>
                    <View style={[styles.alertIconContainer, { backgroundColor: '#F5A623' + '15' }]}>
                      <Ionicons name="people-outline" size={20} color="#F5A623" />
                    </View>
                    <View style={styles.alertContent}>
                      <Text style={[styles.alertTitle, { color: colors.text }]}>Appointments</Text>
                      {data.appointments.map((apt, index) => (
                        <Text key={index} style={[styles.alertText, { color: colors.textSecondary }]}>
                          {apt.visitorName} • {new Date(apt.fromDateTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </Text>
                      ))}
                    </View>
                  </View>
                )}
              </View>
            </View>
          )}

          {/* Quick Actions */}
          <View style={styles.section}>
            <Text style={[styles.sectionTitle, { color: colors.text }]}>Quick Actions</Text>
            <View style={styles.quickActionsGrid}>
              <TouchableOpacity
                style={[styles.quickActionCard, { backgroundColor: colors.card }]}
                onPress={() => router.push({ pathname: '/homework', params: { action: 'create' } })}
              >
                <View style={[styles.quickActionIcon, { backgroundColor: colors.primary + '15' }]}>
                  <Ionicons name="create-outline" size={24} color={colors.primary} />
                </View>
                <Text style={[styles.quickActionText, { color: colors.text }]}>Create{'\n'}Homework</Text>
              </TouchableOpacity>
              <TouchableOpacity
                style={[styles.quickActionCard, { backgroundColor: colors.card }]}
                onPress={() => router.push('/(tabs)/profile')}
              >
                <View style={[styles.quickActionIcon, { backgroundColor: colors.success + '15' }]}>
                  <Ionicons name="time-outline" size={24} color={colors.success} />
                </View>
                <Text style={[styles.quickActionText, { color: colors.text }]}>Apply{'\n'}Leave</Text>
              </TouchableOpacity>
              <TouchableOpacity
