     1→import React, { useState } from 'react';
     2→import {
     3→  View,
     4→  Text,
     5→  Modal,
     6→  TextInput,
     7→  TouchableOpacity,
     8→  StyleSheet,
     9→  ScrollView,
    10→  Alert,
    11→  ActivityIndicator,
    12→} from 'react-native';
    13→import api from '../services/api';
    14→import { format, addDays, parseISO, isValid } from 'date-fns';
    15→import { useTheme } from '../context/ThemeContext';
    16→
    17→interface LeaveApplicationModalProps {
    18→  visible: boolean;
    19→  teacherId: string;
    20→  onClose: () => void;
    21→  onSuccess: () => void;
    22→}
    23→
    24→const LEAVE_TYPES = [
    25→  { value: 'sick', label: 'Sick Leave' },
    26→  { value: 'casual', label: 'Casual Leave' },
    27→  { value: 'earned', label: 'Earned Leave' },
    28→  { value: 'unpaid', label: 'Unpaid Leave' },
    29→  { value: 'other', label: 'Other' },
    30→];
    31→
    32→export default function LeaveApplicationModal({
    33→  visible,
    34→  teacherId,
    35→  onClose,
    36→  onSuccess,
    37→}: LeaveApplicationModalProps) {
    38→  const { colors } = useTheme();
    39→  const [leaveType, setLeaveType] = useState('casual');
    40→  const [reason, setReason] = useState('');
    41→  const [startDate, setStartDate] = useState(format(new Date(), 'yyyy-MM-dd'));
    42→  const [endDate, setEndDate] = useState(format(new Date(), 'yyyy-MM-dd'));
    43→  const [loading, setLoading] = useState(false);
    44→
    45→  const handleSubmit = async () => {
    46→    if (!reason.trim()) {
    47→      Alert.alert('Error', 'Please provide a reason for the leave');
    48→      return;
    49→    }
    50→
    51→    // Validate date format
    52→    const parsedStartDate = parseISO(startDate);
    53→    const parsedEndDate = parseISO(endDate);
    54→
    55→    if (!isValid(parsedStartDate) || !isValid(parsedEndDate)) {
    56→      Alert.alert('Error', 'Please enter valid dates in YYYY-MM-DD format');
    57→      return;
    58→    }
    59→
    60→    // Validate end date is not before start date
    61→    if (parsedEndDate < parsedStartDate) {
    62→      Alert.alert('Error', 'End date cannot be before start date');
    63→      return;
    64→    }
    65→
    66→    setLoading(true);
    67→    try {
    68→      await api.applyForLeave({
    69→        teacherId,
    70→        leaveType,
    71→        reason,
    72→        startDate,
    73→        endDate,
    74→      });
    75→
    76→      Alert.alert('Success', 'Leave application submitted successfully', [
    77→        { text: 'OK', onPress: () => {
    78→          onSuccess();
    79→          onClose();
    80→          setReason('');
    81→          setLeaveType('casual');
    82→          setStartDate(format(new Date(), 'yyyy-MM-dd'));
    83→          setEndDate(format(new Date(), 'yyyy-MM-dd'));
    84→        }},
    85→      ]);
    86→    } catch (error: any) {
    87→      Alert.alert('Error', error.message || 'Failed to submit leave application');
    88→    } finally {
    89→      setLoading(false);
    90→    }
    91→  };
    92→
    93→  return (
    94→    <Modal visible={visible} animationType="slide">
    95→      <View style={[styles.container, { backgroundColor: colors.background }]}>
    96→        <View style={[styles.header, { borderBottomColor: colors.border }]}>
    97→          <Text style={[styles.title, { color: colors.text }]}>Apply for Leave</Text>
    98→          <TouchableOpacity onPress={onClose}>
    99→            <Text style={[styles.closeText, { color: colors.textSecondary }]}>✕</Text>
   100→          </TouchableOpacity>
   101→        </View>
   102→
   103→        <ScrollView style={styles.content}>
   104→          <Text style={[styles.label, { color: colors.text }]}>Leave Type</Text>
   105→          <View style={styles.leaveTypesContainer}>
   106→            {LEAVE_TYPES.map((type) => (
   107→              <TouchableOpacity
   108→                key={type.value}
   109→                style={[
   110→                  styles.leaveTypeButton,
   111→                  { backgroundColor: colors.inputBackground, borderColor: colors.border },
   112→                  leaveType === type.value && { backgroundColor: colors.primary + '15', borderColor: colors.primary },
   113→                ]}
   114→                onPress={() => setLeaveType(type.value)}
   115→              >
   116→                <Text
   117→                  style={[
   118→                    styles.leaveTypeText,
   119→                    { color: colors.textSecondary },
   120→                    leaveType === type.value && { color: colors.primary, fontWeight: '600' },
   121→                  ]}
   122→                >
   123→                  {type.label}
   124→                </Text>
   125→              </TouchableOpacity>
   126→            ))}
   127→          </View>
   128→
   129→          <Text style={[styles.label, { color: colors.text }]}>Start Date</Text>
   130→          <TextInput
   131→            style={[styles.input, { backgroundColor: colors.inputBackground, borderColor: colors.border, color: colors.text }]}
   132→            value={startDate}
   133→            onChangeText={setStartDate}
   134→            placeholder="YYYY-MM-DD"
   135→            placeholderTextColor={colors.textSecondary}
   136→          />
   137→
   138→          <Text style={[styles.label, { color: colors.text }]}>End Date</Text>
   139→          <TextInput
   140→            style={[styles.input, { backgroundColor: colors.inputBackground, borderColor: colors.border, color: colors.text }]}
   141→            value={endDate}
   142→            onChangeText={setEndDate}
   143→            placeholder="YYYY-MM-DD"
   144→            placeholderTextColor={colors.textSecondary}
   145→          />
   146→
   147→          <Text style={[styles.label, { color: colors.text }]}>Reason</Text>
   148→          <TextInput
   149→            style={[styles.input, styles.textArea, { backgroundColor: colors.inputBackground, borderColor: colors.border, color: colors.text }]}
   150→            value={reason}
   151→            onChangeText={setReason}
   152→            placeholder="Enter reason for leave"
   153→            placeholderTextColor={colors.textSecondary}
   154→            multiline
   155→            numberOfLines={4}
   156→            textAlignVertical="top"
   157→          />
   158→
   159→          <TouchableOpacity
   160→            style={[styles.submitButton, { backgroundColor: colors.primary }, loading && styles.submitButtonDisabled]}
   161→            onPress={handleSubmit}
   162→            disabled={loading}
   163→          >
