import React, { useState } from 'react';
import {
  View,
  Text,
  Modal,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  ScrollView,
  Alert,
  ActivityIndicator,
} from 'react-native';
import api from '../services/api';
import { useTheme } from '../context/ThemeContext';
import { Ionicons } from '@expo/vector-icons';

interface Student {
  id: string;
  name: string;
  rollNo: number;
}

interface StudentRemarksModalProps {
  visible: boolean;
  student: Student | null;
  onClose: () => void;
  onSuccess: () => void;
}

const REMARK_CATEGORIES = [
  { value: 'general', label: 'General' },
  { value: 'academic', label: 'Academic' },
  { value: 'behavior', label: 'Behavior' },
  { value: 'attendance', label: 'Attendance' },
  { value: 'achievement', label: 'Achievement' },
  { value: 'concern', label: 'Concern' },
];

export default function StudentRemarksModal({
  visible,
  student,
  onClose,
  onSuccess,
}: StudentRemarksModalProps) {
  const { colors } = useTheme();
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('general');
  const [sentToParent, setSentToParent] = useState(true);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    if (!student) return;

    if (!title.trim() || !description.trim()) {
      Alert.alert('Error', 'Please fill all required fields');
      return;
    }

    setLoading(true);
    try {
      await api.createRemark(student.id, {
        title,
        description,
        category,
        sentToParent,
      });

      Alert.alert('Success', 'Remark added successfully', [
        {
          text: 'OK',
          onPress: () => {
            onSuccess();
            handleClose();
          },
        },
      ]);
    } catch (error: any) {
      Alert.alert('Error', error.message || 'Failed to add remark');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setTitle('');
    setDescription('');
    setCategory('general');
    setSentToParent(true);
    onClose();
  };

  if (!student) return null;

  return (
    <Modal visible={visible} animationType="slide" transparent>
      <View style={{ flex: 1, justifyContent: 'flex-end', backgroundColor: 'rgba(0, 0, 0, 0.5)' }}>
        <View style={{ backgroundColor: colors.card, borderTopLeftRadius: 24, borderTopRightRadius: 24, maxHeight: '90%' }}>
          <View style={[styles.header, { borderBottomColor: colors.border }]}>
            <Text style={[styles.title, { color: colors.text }]}>Add Remark</Text>
            <TouchableOpacity onPress={handleClose}>
              <Ionicons name="close" size={24} color={colors.textSecondary} />
            </TouchableOpacity>
          </View>

          <ScrollView style={styles.content} showsVerticalScrollIndicator={false}>
            <View style={[styles.studentInfo, { backgroundColor: colors.primary + '15' }]}>
              <Text style={[styles.studentName, { color: colors.text }]}>{student.name}</Text>
              <Text style={[styles.studentRollNo, { color: colors.textSecondary }]}>Roll No: {student.rollNo}</Text>
            </View>

            <Text style={[styles.label, { color: colors.text }]}>Category</Text>
            <View style={styles.categoriesContainer}>
              {REMARK_CATEGORIES.map((cat) => (
                <TouchableOpacity
                  key={cat.value}
                  style={[
                    styles.categoryButton,
                    { backgroundColor: colors.inputBackground, borderColor: colors.border },
                    category === cat.value && { backgroundColor: colors.primary + '15', borderColor: colors.primary },
                  ]}
                  onPress={() => setCategory(cat.value)}
                >
                  <Text
                    style={[
                      styles.categoryText,
                      { color: colors.textSecondary },
                      category === cat.value && { color: colors.primary, fontWeight: '600' },
                    ]}
                  >
                    {cat.label}
                  </Text>
                </TouchableOpacity>
              ))}
            </View>

            <Text style={[styles.label, { color: colors.text }]}>Title *</Text>
            <TextInput
              style={[styles.input, { backgroundColor: colors.inputBackground, borderColor: colors.border, color: colors.text }]}
              value={title}
              onChangeText={setTitle}
              placeholder="Enter title"
              placeholderTextColor={colors.textSecondary}
            />

            <Text style={[styles.label, { color: colors.text }]}>Description *</Text>
            <TextInput
              style={[styles.input, styles.textArea, { backgroundColor: colors.inputBackground, borderColor: colors.border, color: colors.text }]}
              value={description}
              onChangeText={setDescription}
              placeholder="Enter description"
              placeholderTextColor={colors.textSecondary}
              multiline
              numberOfLines={5}
              textAlignVertical="top"
            />

            <TouchableOpacity
              style={[
                styles.parentToggle,
                { backgroundColor: colors.inputBackground, borderColor: colors.border },
                sentToParent && { backgroundColor: colors.success + '20', borderColor: colors.success },
              ]}
              onPress={() => setSentToParent(!sentToParent)}
            >
              <Ionicons
                name={sentToParent ? 'checkmark-circle' : 'ellipse-outline'}
                size={20}
                color={sentToParent ? colors.success : colors.textSecondary}
                style={{ marginRight: 8 }}
              />
              <Text
                style={[
                  { fontSize: 16, fontWeight: '500', color: colors.textSecondary },
                  sentToParent && { color: colors.success },
                ]}
              >
                Send to Parent
              </Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[styles.submitButton, { backgroundColor: colors.primary }, loading && styles.submitButtonDisabled]}
              onPress={handleSubmit}
              disabled={loading}
            >
              {loading ? (
                <ActivityIndicator color={colors.white} />
              ) : (
                <Text style={[styles.submitButtonText, { color: colors.white }]}>Submit Remark</Text>
              )}
            </TouchableOpacity>
          </ScrollView>
        </View>
      </View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: 20,
    borderBottomWidth: 1,
  },
  title: {
    fontSize: 20,
    fontWeight: 'bold',
  },
  content: {
    padding: 20,
  },
  studentInfo: {
    padding: 16,
    borderRadius: 12,
    marginBottom: 20,
  },
  studentName: {
    fontSize: 18,
    fontWeight: 'bold',
  },
  studentRollNo: {
    fontSize: 14,
    marginTop: 4,
  },
  label: {
    fontSize: 14,
    fontWeight: '600',
    marginBottom: 8,
    marginTop: 16,
  },
  categoriesContainer: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 8,
  },
  categoryButton: {
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 16,
    borderWidth: 1,
  },
  categoryText: {
    fontSize: 13,
  },
  input: {
    borderWidth: 1,
    borderRadius: 12,
    padding: 14,
    fontSize: 16,
  },
  textArea: {
    height: 120,
  },
  parentToggle: {
    flexDirection: 'row',
    alignItems: 'center',
    padding: 16,
    borderRadius: 12,
    borderWidth: 2,
    marginTop: 16,
  },
  submitButton: {
    padding: 16,
    borderRadius: 12,
    alignItems: 'center',
    marginTop: 24,
    marginBottom: 24,
  },
  submitButtonDisabled: {
    opacity: 0.7,
  },
  submitButtonText: {
    fontSize: 16,
    fontWeight: '600',
  },
});

