import React, { useEffect, useState, useCallback } from 'react';
import {
    View,
    Text,
    ScrollView,
    StyleSheet,
    ActivityIndicator,
    Alert,
    Image,
    TouchableOpacity,
} from 'react-native';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { useRouter, Stack } from 'expo-router';
import api from '../services/api';
import { Ionicons } from '@expo/vector-icons';

export default function ClassDetailsScreen() {
    const { user } = useAuth();
    const { colors } = useTheme();
    const router = useRouter();
    const [data, setData] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    const loadClassStudents = useCallback(async () => {
        if (!user?.id) return;
        try {
            const response = await api.getClassStudents(user.id);
            setData(response);
        } catch (error: any) {
            console.error('Error loading class students:', error);
            Alert.alert('Error', error.message || 'Failed to load class details');
        } finally {
            setLoading(false);
        }
    }, [user?.id]);

    useEffect(() => {
        loadClassStudents();
    }, [loadClassStudents]);

    if (loading) {
        return (
            <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }}>
                <ActivityIndicator size="large" color={colors.primary} />
            </View>
        );
    }

    if (!data || !data.class) {
        return (
            <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }}>
                <Text style={{ fontSize: 16, color: colors.textSecondary, textAlign: 'center' }}>No class information available</Text>
            </View>
        );
    }

    return (
        <>
            <Stack.Screen options={{ title: 'Class Details', headerShown: true }} />
            <ScrollView style={{ flex: 1, backgroundColor: colors.backgroundGray }}>
                <View style={{ padding: 24, backgroundColor: colors.primary, alignItems: 'center' }}>
                    <Text style={{ fontSize: 24, fontWeight: 'bold', color: colors.white }}>{data.class.name} {data.class.section}</Text>
                    <Text style={{ fontSize: 16, color: colors.white + 'CC', marginTop: 4 }}>{data.students.length} Students</Text>
                </View>

                <View style={{ flexDirection: 'row', padding: 16, paddingBottom: 0, gap: 12 }}>
                    <TouchableOpacity
                        style={{ flex: 1, backgroundColor: colors.card, padding: 16, borderRadius: 12, alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 1 }}
                        onPress={() => router.push('/attendance')}
                    >
                        <View style={{ width: 48, height: 48, borderRadius: 24, backgroundColor: colors.primary + '15', justifyContent: 'center', alignItems: 'center', marginBottom: 8 }}>
                            <Ionicons name="calendar-outline" size={24} color={colors.primary} />
                        </View>
                        <Text style={{ fontSize: 14, fontWeight: '600', color: colors.text }}>Attendance</Text>
                    </TouchableOpacity>

                    <TouchableOpacity
                        style={{ flex: 1, backgroundColor: colors.card, padding: 16, borderRadius: 12, alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 1 }}
                        onPress={() => router.push('/homework')}
                    >
                        <View style={{ width: 48, height: 48, borderRadius: 24, backgroundColor: colors.primary + '15', justifyContent: 'center', alignItems: 'center', marginBottom: 8 }}>
                            <Ionicons name="book-outline" size={24} color={colors.primary} />
                        </View>
                        <Text style={{ fontSize: 14, fontWeight: '600', color: colors.text }}>Homework</Text>
                    </TouchableOpacity>
                </View>

                <Text style={{ fontSize: 18, fontWeight: 'bold', color: colors.text, margin: 16, marginBottom: 8 }}>Students List</Text>

                {data.students.map((student: any, index: number) => (
                    <TouchableOpacity
                        key={student.id}
                        style={{ flexDirection: 'row', alignItems: 'center', padding: 16, marginHorizontal: 16, marginBottom: 12, backgroundColor: colors.card, borderRadius: 12, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.1, shadowRadius: 2, elevation: 2 }}
                        onPress={() => router.push({ pathname: '/student-details', params: { id: student.id } })}
                    >
                        <View style={{ width: 48, height: 48, borderRadius: 24, backgroundColor: colors.primary + '15', justifyContent: 'center', alignItems: 'center', marginRight: 16 }}>
                            <Text style={{ fontSize: 20, fontWeight: 'bold', color: colors.primary }}>{student.name.charAt(0)}</Text>
                        </View>
                        <View style={{ flex: 1 }}>
                            <Text style={{ fontSize: 16, fontWeight: '600', color: colors.text }}>{student.name}</Text>
                            <Text style={{ fontSize: 14, color: colors.textSecondary, marginTop: 2 }}>Roll No: {student.rollNo}</Text>
                        </View>
                    </TouchableOpacity>
                ))}
            </ScrollView>
        </>
    );
}

